+//! Speculative Decoding Scheduler
+//!
+//! Implements heterogeneous speculative decoding:
+//! - Draft model: Small model (Q2/Q4) runs on GPU for fast candidate generation
+//! - Target model: Large model runs on CPU with mmap for memory efficiency
+//!
+//! This allows running models larger than RAM by:
+//! 1. Draft generates K candidate tokens quickly (GPU, ~100 tok/s)
+//! 2. Target verifies all K tokens in one forward pass (CPU, mmap streaming)
+//! 3. Accept N tokens where draft matches target (N ≤ K)
+//! 4. Amortize slow CPU/SSD cost over multiple tokens
+
+const std = @import("std");
+const llama = @import("llama.zig");
+const profile_mod = @import("profile.zig");
+const c = llama.c;
+
+/// Speculative decoding configuration
+pub const SpeculativeConfig = struct {
+    /// Number of candidate tokens to generate per speculation round
+    speculation_depth: u32 = 8,
+    /// Temperature for draft model (slightly higher for diversity)
+    draft_temperature: f32 = 0.8,
+    /// Temperature for target model verification
+    target_temperature: f32 = 0.7,
+    /// Maximum tokens to generate
+    max_tokens: u32 = 256,
+    /// Callback for streaming tokens
+    on_token: ?*const fn ([]const u8) void = null,
+};
+
+/// Dual-model context for speculative decoding
+pub const SpeculativeContext = struct {
+    allocator: std.mem.Allocator,
+
+    // Draft model - small, fast, GPU-resident
+    draft_model: llama.Model,
+    draft_ctx: llama.Context,
+
+    // Target model - large, CPU-only with mmap
+    target_model: llama.Model,
+    target_ctx: llama.Context,
+
+    // Statistics
+    total_tokens: u64 = 0,
+    accepted_tokens: u64 = 0,
+    speculation_rounds: u64 = 0,
+
+    const Self = @This();
+
+    /// Initialize speculative context with draft and target models
+    pub fn init(
+        allocator: std.mem.Allocator,
+        draft_path: []const u8,
+        target_path: []const u8,
+        prof: profile_mod.Profile,
+    ) !*Self {
+        std.debug.print("\n🚀 Initializing Speculative Decoding\n", .{});
+        std.debug.print("   Draft model (GPU): {s}\n", .{draft_path});
+        std.debug.print("   Target model (CPU/mmap): {s}\n", .{target_path});
+
+        // Allocate self first so we can take stable pointers to models
+        const self = try allocator.create(Self);
+        errdefer allocator.destroy(self);
+
+        // Load draft model on GPU (all layers)
+        std.debug.print("\n📦 Loading draft model (GPU)...\n", .{});
+        self.draft_model = try loadDraftModel(draft_path, prof);
+        errdefer self.draft_model.deinit();
+
+        self.draft_ctx = try llama.Context.init(&self.draft_model, .{
+            .n_ctx = prof.optimal_config.n_ctx,
+            .n_batch = prof.optimal_config.n_batch,
+        });
+        errdefer self.draft_ctx.deinit();
+
+        // Load target model on CPU only (0 GPU layers, mmap enabled)
+        std.debug.print("📦 Loading target model (CPU/mmap)...\n", .{});
+        self.target_model = try loadTargetModel(target_path);
+        errdefer self.target_model.deinit();
+
+        self.target_ctx = try llama.Context.init(&self.target_model, .{
+            .n_ctx = prof.optimal_config.n_ctx,
+            .n_batch = prof.optimal_config.n_batch,
+        });
+        errdefer self.target_ctx.deinit();
+
+        self.allocator = allocator;
+        self.total_tokens = 0;
+        self.accepted_tokens = 0;
+        self.speculation_rounds = 0;
+
+        std.debug.print("✅ Speculative decoding ready\n\n", .{});
+
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.target_ctx.deinit();
+        self.target_model.deinit();
+        self.draft_ctx.deinit();
+        self.draft_model.deinit();
+        self.allocator.destroy(self);
+    }
+
+    /// Generate tokens using speculative decoding
+    /// Algorithm:
+    /// 1. Draft model generates K candidate tokens (fast, GPU)
+    /// 2. Target model verifies all K tokens in one batch (slow, CPU/mmap)
+    /// 3. Accept tokens until first mismatch
+    /// 4. Resample from target at mismatch point
+    /// 5. Repeat until max_tokens or EOS
+    pub fn generate(self: *Self, prompt: []const u8, config: SpeculativeConfig) !void {
+        const draft_vocab = self.draft_model.getVocab();
