+        for (0..n_tokens) |i| {
+            draft_batch.token[i] = tokens[i];
+            draft_batch.pos[i] = @intCast(i);
+            draft_batch.n_seq_id[i] = 1;
+            draft_batch.seq_id[i][0] = 0;
+            draft_batch.logits[i] = 0;
+        }
+        draft_batch.logits[n_tokens - 1] = 1;
+        draft_batch.n_tokens = @intCast(n_tokens);
+
+        std.debug.print("Processing prompt in draft model...\n", .{});
+        if (c.llama_decode(self.draft_ctx.handle, draft_batch) != 0) {
+            return error.DraftPromptFailed;
+        }
+
+        // Process in target model
+        var target_batch = c.llama_batch_init(@intCast(n_tokens), 0, 1);
+        defer c.llama_batch_free(target_batch);
+
+        for (0..n_tokens) |i| {
+            target_batch.token[i] = tokens[i];
+            target_batch.pos[i] = @intCast(i);
+            target_batch.n_seq_id[i] = 1;
+            target_batch.seq_id[i][0] = 0;
+            target_batch.logits[i] = 0;
+        }
+        target_batch.logits[n_tokens - 1] = 1;
+        target_batch.n_tokens = @intCast(n_tokens);
+
+        std.debug.print("Processing prompt in target model...\n", .{});
+        if (c.llama_decode(self.target_ctx.handle, target_batch) != 0) {
+            return error.TargetPromptFailed;
+        }
+    }
