+            std.debug.print("   Total tokens: {}\n", .{self.total_tokens});
+            std.debug.print("   Accepted (draft matched): {}\n", .{self.accepted_tokens});
+            std.debug.print("   Acceptance rate: {d:.1}%\n", .{acceptance_rate});
+            std.debug.print("   Speculation rounds: {}\n", .{self.speculation_rounds});
+        }
+    }
+};
+
+/// Load draft model with GPU acceleration
+fn loadDraftModel(path: []const u8, prof: profile_mod.Profile) !llama.Model {
+    // Use the Model.load API with GPU layers for draft
+    return llama.Model.load(path, .{
+        .n_gpu_layers = prof.optimal_config.n_gpu_layers,
+        .use_mmap = true,
+        .use_mlock = false,
+    });
+}
+
+/// Load target model on CPU only (no GPU layers) with mmap for streaming
+fn loadTargetModel(path: []const u8) !llama.Model {
+    std.debug.print("   n_gpu_layers: 0 (CPU only)\n", .{});
+    std.debug.print("   use_mmap: true (SSD streaming)\n", .{});
+
+    // CRITICAL: CPU only to prevent Metal from wiring memory
+    return llama.Model.load(path, .{
+        .n_gpu_layers = 0, // No GPU - pure CPU
+        .use_mmap = true, // Enable mmap for on-demand page loading
+        .use_mlock = false, // Don't lock pages in RAM
+    });
+}
+
+/// Check if speculative decoding should be used
+pub fn shouldUseSpeculative(prof: profile_mod.Profile) bool {
+    // Use speculative if we have a draft model configured
+    return prof.draft_model_path != null;
+}
+
+/// Run inference with speculative decoding
+pub fn runSpeculativeInference(
+    allocator: std.mem.Allocator,
+    target_path: []const u8,
+    prompt: []const u8,
+    prof: profile_mod.Profile,
+    config: SpeculativeConfig,
