+    const draft_path = prof.draft_model_path orelse {
+        std.debug.print("Error: No draft model configured\n", .{});
+        std.debug.print("Run: zell build {s} --draft <draft-model.gguf>\n", .{target_path});
+        return error.NoDraftModel;
+    };
+
+    const ctx = try SpeculativeContext.init(allocator, draft_path, target_path, prof);
+    defer ctx.deinit();
+
+    try ctx.generate(prompt, config);
+    ctx.printStats();
+}

